export const generateFlashcards = async (
    subject: string, 
    topic: string, 
    count: number, 
    grade: string, 
    language: Language
): Promise<Flashcard[]> => {

    // 1. Try to fetch from DB first
    if (db) {
        try {
            const docId = createDocId(grade, subject, topic, language);
            const docRef = doc(db, 'flashcards', docId);
            const docSnap = await getDoc(docRef);

            if (docSnap.exists()) {
                console.log("✅ Flashcards fetched from Firebase (Saved Credits!)");
                return docSnap.data().cards as Flashcard[];
            }
        } catch (e) {
            console.warn("Flashcard fetch error", e);
        }
      }

    // 2. Fallback to AI
    console.log("Creating new Flashcards via AI...");
    const response = await generateWithFallback(MODEL_FAST, MODEL_COMPLEX, {
      contents: `Generate ${count} flashcards for ${grade} ${subject} topic ${topic}. Language: ${language}. Output JSON.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: { front: { type: Type.STRING }, back: { type: Type.STRING } },
            required: ["front", "back"]
          }
        }
      }
    });
    const text = response.text;
    if (!text) throw new Error("No response");
    const cards = JSON.parse(text.trim()) as Flashcard[];

    // 3. Save to DB
    if (db && cards.length > 0) {
        try {
            const docId = createDocId(grade, subject, topic, language);
            await setDoc(doc(db, 'flashcards', docId), { 
                cards, 
                createdAt: new Date().toISOString() 
            });
            console.log("💾 Flashcards saved to Firebase for future use.");
        } catch (e) {
            console.warn("Failed to save flashcards", e);
        }
    }

    return cards;
};

